238.operations:
{
    size := extcodesize(target)
    let buf := mload(0x40)
    switch size
    case 0 { head := 0 }
    default {
        extcodecopy(target, buf, 0, 32)
        head := mload(buf)
    }
    for { let i := 0 } lt(i, 2) { i := add(i, 1) }
    { pop(add(i, 1)) }
    function double(x) -> y
    { y := mul(x, 2) }
    pop(double(3))
}

